const functions = require('firebase-functions');
const admin = require('firebase-admin');
admin.initializeApp();

exports.novaResposta = functions.firestore
  .document('respostas/{respostaId}')
  .onCreate(async (snap, context) => {
    const dados = snap.data();
    console.log('Nova resposta:', context.params.respostaId, '- XP:', dados.xp);
  });

